import { describe, it, expect, beforeEach, vi } from 'vitest';
import { ScraperSourceService } from '../services/scraperSourceService';
import { ScraperQueueService } from '../services/scraperQueueService';

describe('Scraper Management', () => {
  let sourceService: ScraperSourceService;
  let queueService: ScraperQueueService;

  beforeEach(() => {
    sourceService = new ScraperSourceService();
    queueService = new ScraperQueueService();
  });

  describe('ScraperSourceService - CRUD Operations', () => {
    it('should create a new scraper source with valid data', async () => {
      const sourceData = {
        name: 'Test Anime Source',
        url: 'https://example.com',
        type: 'ANIME' as const,
        selector: '.content',
        timeout: 30000,
        retryCount: 3,
        retryDelay: 1000,
