/**
 * SEO Service
 * Manages SEO-related functionality: sitemap, robots.txt, redirects, 404 pages
 */

import { logger } from './loggerService';
import { createAppError } from '../middleware/errorHandler';
import { ErrorCode } from '../constants/errorCodes';

/**
 * SEO Configuration Interface
 */
export interface SeoConfig {
  siteTitle: string;
  siteDescription: string;
  siteKeywords: string[];
  ogImage?: string;
  twitterHandle?: string;
  canonicalUrl?: string;
  sitemapEnabled: boolean;
  robotsTxtEnabled: boolean;
  updatedAt: Date;
}

/**
 * Redirect Rule Interface
 */
export interface RedirectRule {
  id: string;
  fromUrl: string;
  toUrl: string;
  statusCode: '301' | '302' | '307' | '308';
  enabled: boolean;
  hitCount: number;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * 404 Page Configuration
 */
export interface NotFoundPageConfig {
  content: string;
  customHtml?: string;
  showSuggestions: boolean;
  updatedAt: Date;
}

/**
 * Sitemap URL Entry
 */
export interface SitemapUrl {
  loc: string;
  lastmod?: string;
  changefreq?: 'always' | 'hourly' | 'daily' | 'weekly' | 'monthly' | 'yearly' | 'never';
  priority?: number;
}

/**
 * SEO Service Class
 */
export class SeoService {
  private seoConfig: SeoConfig;
  private redirectRules: Map<string, RedirectRule>;
  private notFoundConfig: NotFoundPageConfig;

  constructor() {
    // Initialize with default config
    this.seoConfig = {
      siteTitle: 'Audira Zenith',
      siteDescription: 'Platform streaming anime, manga, dan donghua terbaik',
      siteKeywords: ['anime', 'manga', 'donghua', 'streaming', 'online'],
      sitemapEnabled: true,
      robotsTxtEnabled: true,
      updatedAt: new Date(),
    };

    this.redirectRules = new Map();
    this.notFoundConfig = {
      content: 'Halaman tidak ditemukan',
      showSuggestions: true,
      updatedAt: new Date(),
    };
  }

  /**
   * Generate XML Sitemap
   */
  async generateSitemap(urls?: SitemapUrl[]): Promise<string> {
    try {
      if (!this.seoConfig.sitemapEnabled) {
        throw createAppError(
          'Sitemap generation is disabled',
          ErrorCode.BAD_REQUEST,
          400
        );
      }

      // Default URLs if none provided
      const sitemapUrls: SitemapUrl[] = urls || [
        {
          loc: '/',
          changefreq: 'daily',
          priority: 1.0,
        },
        {
          loc: '/anime',
          changefreq: 'daily',
          priority: 0.9,
        },
        {
          loc: '/manga',
          changefreq: 'daily',
          priority: 0.9,
        },
        {
          loc: '/donghua',
          changefreq: 'daily',
          priority: 0.9,
        },
      ];

      // Build XML
      let xml = '<?xml version="1.0" encoding="UTF-8"?>\n';
      xml += '<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n';

      for (const url of sitemapUrls) {
        xml += '  <url>\n';
        xml += `    <loc>${this.escapeXml(url.loc)}</loc>\n`;

        if (url.lastmod) {
          xml += `    <lastmod>${url.lastmod}</lastmod>\n`;
        }

        if (url.changefreq) {
          xml += `    <changefreq>${url.changefreq}</changefreq>\n`;
        }

        if (url.priority !== undefined) {
          xml += `    <priority>${url.priority.toFixed(1)}</priority>\n`;
        }

        xml += '  </url>\n';
      }

      xml += '</urlset>';

      logger.info('Sitemap generated', {
        urlCount: sitemapUrls.length,
      });

      return xml;
    } catch (error) {
      logger.error('Failed to generate sitemap', error as Error);
      throw error;
    }
  }

  /**
   * Generate robots.txt
   */
  async generateRobotsTxt(options?: {
    disallowPaths?: string[];
    allowPaths?: string[];
    sitemapUrl?: string;
  }): Promise<string> {
    try {
      if (!this.seoConfig.robotsTxtEnabled) {
        throw createAppError(
          'Robots.txt generation is disabled',
          ErrorCode.BAD_REQUEST,
          400
        );
      }

      const disallowPaths = options?.disallowPaths || ['/admin', '/api'];
      const allowPaths = options?.allowPaths || [];
      const sitemapUrl = options?.sitemapUrl || '/sitemap.xml';

      let robotsTxt = '# Audira Zenith - robots.txt\n';
      robotsTxt += '# Generated on ' + new Date().toISOString() + '\n\n';

      robotsTxt += 'User-agent: *\n';

      // Add disallow rules
      for (const path of disallowPaths) {
        robotsTxt += `Disallow: ${path}\n`;
      }

      // Add allow rules
      for (const path of allowPaths) {
        robotsTxt += `Allow: ${path}\n`;
      }

      robotsTxt += '\n';

      // Add sitemap
      robotsTxt += `Sitemap: ${sitemapUrl}\n`;

      logger.info('Robots.txt generated', {
        disallowCount: disallowPaths.length,
        allowCount: allowPaths.length,
      });

      return robotsTxt;
    } catch (error) {
      logger.error('Failed to generate robots.txt', error as Error);
      throw error;
    }
  }

  /**
   * Create redirect rule
   */
  async createRedirect(data: {
    fromUrl: string;
    toUrl: string;
    statusCode?: '301' | '302' | '307' | '308';
  }): Promise<RedirectRule> {
    try {
      // Validate URLs
      this.validateUrl(data.fromUrl);
      this.validateUrl(data.toUrl);

      // Check for duplicate
      for (const rule of this.redirectRules.values()) {
        if (rule.fromUrl === data.fromUrl) {
          throw createAppError(
            'Redirect rule already exists for this URL',
            ErrorCode.BAD_REQUEST,
            400
          );
        }
      }

      const redirect: RedirectRule = {
        id: `redirect-${Date.now()}`,
        fromUrl: data.fromUrl,
        toUrl: data.toUrl,
        statusCode: data.statusCode || '301',
        enabled: true,
        hitCount: 0,
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      this.redirectRules.set(redirect.id, redirect);

      logger.info('Redirect rule created', {
        id: redirect.id,
        fromUrl: redirect.fromUrl,
        toUrl: redirect.toUrl,
        statusCode: redirect.statusCode,
      });

      return redirect;
    } catch (error) {
      logger.error('Failed to create redirect rule', error as Error, { data });
      throw error;
    }
  }

  /**
   * Update redirect rule
   */
  async updateRedirect(
    id: string,
    data: Partial<{
      toUrl: string;
      statusCode: '301' | '302' | '307' | '308';
      enabled: boolean;
    }>
  ): Promise<RedirectRule> {
    try {
      const redirect = this.redirectRules.get(id);

      if (!redirect) {
        throw createAppError(
          'Redirect rule not found',
          ErrorCode.NOT_FOUND,
          404
        );
      }

      // Validate toUrl if provided
      if (data.toUrl) {
        this.validateUrl(data.toUrl);
        redirect.toUrl = data.toUrl;
      }

      if (data.statusCode) {
        redirect.statusCode = data.statusCode;
      }

      if (data.enabled !== undefined) {
        redirect.enabled = data.enabled;
      }

      redirect.updatedAt = new Date();

      logger.info('Redirect rule updated', {
        id,
        changes: Object.keys(data),
      });

      return redirect;
    } catch (error) {
      logger.error('Failed to update redirect rule', error as Error, { id, data });
      throw error;
    }
  }

  /**
   * Delete redirect rule
   */
  async deleteRedirect(id: string): Promise<void> {
    try {
      const redirect = this.redirectRules.get(id);

      if (!redirect) {
        throw createAppError(
          'Redirect rule not found',
          ErrorCode.NOT_FOUND,
          404
        );
      }

      this.redirectRules.delete(id);

      logger.info('Redirect rule deleted', { id });
    } catch (error) {
      logger.error('Failed to delete redirect rule', error as Error, { id });
      throw error;
    }
  }

  /**
   * List redirect rules
   */
  async listRedirects(filters?: {
    enabled?: boolean;
    search?: string;
  }): Promise<RedirectRule[]> {
    try {
      let redirects = Array.from(this.redirectRules.values());

      // Filter by enabled status
      if (filters?.enabled !== undefined) {
        redirects = redirects.filter(r => r.enabled === filters.enabled);
      }

      // Filter by search
      if (filters?.search) {
        const search = filters.search.toLowerCase();
        redirects = redirects.filter(
          r =>
            r.fromUrl.toLowerCase().includes(search) ||
            r.toUrl.toLowerCase().includes(search)
        );
      }

      // Sort by creation date (newest first)
      redirects.sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime());

      return redirects;
    } catch (error) {
      logger.error('Failed to list redirect rules', error as Error, { filters });
      throw error;
    }
  }

  /**
   * Get redirect rule by ID
   */
  async getRedirect(id: string): Promise<RedirectRule> {
    try {
      const redirect = this.redirectRules.get(id);

      if (!redirect) {
        throw createAppError(
          'Redirect rule not found',
          ErrorCode.NOT_FOUND,
          404
        );
      }

      return redirect;
    } catch (error) {
      logger.error('Failed to get redirect rule', error as Error, { id });
      throw error;
    }
  }

  /**
   * Find redirect for URL
   */
  async findRedirect(url: string): Promise<RedirectRule | null> {
    try {
      for (const redirect of this.redirectRules.values()) {
        if (redirect.enabled && redirect.fromUrl === url) {
          // Increment hit count
          redirect.hitCount++;
          return redirect;
        }
      }

      return null;
    } catch (error) {
      logger.error('Failed to find redirect', error as Error, { url });
      throw error;
    }
  }

  /**
   * Get 404 page configuration
   */
  async get404Page(): Promise<NotFoundPageConfig> {
    try {
      return this.notFoundConfig;
    } catch (error) {
      logger.error('Failed to get 404 page config', error as Error);
      throw error;
    }
  }

  /**
   * Update 404 page configuration
   */
  async update404Page(data: {
    content?: string;
    customHtml?: string;
    showSuggestions?: boolean;
  }): Promise<NotFoundPageConfig> {
    try {
      if (data.content) {
        this.notFoundConfig.content = data.content;
      }

      if (data.customHtml !== undefined) {
        this.notFoundConfig.customHtml = data.customHtml;
      }

      if (data.showSuggestions !== undefined) {
        this.notFoundConfig.showSuggestions = data.showSuggestions;
      }

      this.notFoundConfig.updatedAt = new Date();

      logger.info('404 page config updated', {
        changes: Object.keys(data),
      });

      return this.notFoundConfig;
    } catch (error) {
      logger.error('Failed to update 404 page config', error as Error, { data });
      throw error;
    }
  }

  /**
   * Get SEO configuration
   */
  async getSeoConfig(): Promise<SeoConfig> {
    try {
      return this.seoConfig;
    } catch (error) {
      logger.error('Failed to get SEO config', error as Error);
      throw error;
    }
  }

  /**
   * Update SEO configuration
   */
  async updateSeoConfig(data: Partial<SeoConfig>): Promise<SeoConfig> {
    try {
      if (data.siteTitle) {
        this.seoConfig.siteTitle = data.siteTitle;
      }

      if (data.siteDescription) {
        this.seoConfig.siteDescription = data.siteDescription;
      }

      if (data.siteKeywords) {
        this.seoConfig.siteKeywords = data.siteKeywords;
      }

      if (data.ogImage !== undefined) {
        this.seoConfig.ogImage = data.ogImage;
      }

      if (data.twitterHandle !== undefined) {
        this.seoConfig.twitterHandle = data.twitterHandle;
      }

      if (data.canonicalUrl !== undefined) {
        this.seoConfig.canonicalUrl = data.canonicalUrl;
      }

      if (data.sitemapEnabled !== undefined) {
        this.seoConfig.sitemapEnabled = data.sitemapEnabled;
      }

      if (data.robotsTxtEnabled !== undefined) {
        this.seoConfig.robotsTxtEnabled = data.robotsTxtEnabled;
      }

      this.seoConfig.updatedAt = new Date();

      logger.info('SEO config updated', {
        changes: Object.keys(data),
      });

      return this.seoConfig;
    } catch (error) {
      logger.error('Failed to update SEO config', error as Error, { data });
      throw error;
    }
  }

  /**
   * Validate URL
   */
  private validateUrl(url: string): void {
    if (!url || url.trim().length === 0) {
      throw createAppError(
        'URL cannot be empty',
        ErrorCode.VALIDATION_ERROR,
        400
      );
    }

    // Allow relative URLs (starting with /)
    if (url.startsWith('/')) {
      return;
    }

    // Validate absolute URLs
    try {
      new URL(url);
    } catch {
      throw createAppError(
        'Invalid URL format',
        ErrorCode.VALIDATION_ERROR,
        400
      );
    }
  }

  /**
   * Escape XML special characters
   */
  private escapeXml(str: string): string {
    return str
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&apos;');
  }
}

// Export singleton instance
export const seoService = new SeoService();

/**
 * SEO Management Routes
 * API endpoints for SEO management: sitemap, robots.txt, redirects, 404 pages
 */

import { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
import { seoService } from '../services/seoService';
import { logger } from '../services/loggerService';
import { validate } from '../middleware/validation';
import { schemas } from '../schemas/validationSchemas';
import { rateLimitByIP, rateLimitConfigs } from '../middleware/rateLimiting';
import { z } from 'zod';

/**
 * Register SEO management routes
 */
export async function seoRoutes(fastify: FastifyInstance) {
  // ==================== PUBLIC ENDPOINTS ====================

  /**
   * GET /api/seo/sitemap.xml
   * Get XML sitemap (public)
   */
  fastify.get(
    '/api/seo/sitemap.xml',
    {
      preHandler: [
        rateLimitByIP(rateLimitConfigs.public.default.limit, rateLimitConfigs.public.default.window),
      ],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const sitemap = await seoService.generateSitemap();

        logger.info('Sitemap requested', {
          requestId: request.id,
          ip: request.ip,
        });

        return reply
          .type('application/xml')
          .send(sitemap);
      } catch (error) {
        logger.error('Failed to generate sitemap', error as Error, {
          requestId: request.id,
        });
        throw error;
      }
    }
  );

  /**
   * GET /api/seo/robots.txt
   * Get robots.txt (public)
   */
  fastify.get(
    '/api/seo/robots.txt',
    {
      preHandler: [
        rateLimitByIP(rateLimitConfigs.public.default.limit, rateLimitConfigs.public.default.window),
      ],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const robotsTxt = await seoService.generateRobotsTxt();

        logger.info('Robots.txt requested', {
          requestId: request.id,
          ip: request.ip,
        });

        return reply
          .type('text/plain')
          .send(robotsTxt);
      } catch (error) {
        logger.error('Failed to generate robots.txt', error as Error, {
          requestId: request.id,
        });
        throw error;
      }
    }
  );

  /**
   * GET /api/seo/404
   * Get 404 page content (public)
   */
  fastify.get(
    '/api/seo/404',
    {
      preHandler: [
        rateLimitByIP(rateLimitConfigs.public.default.limit, rateLimitConfigs.public.default.window),
      ],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const config = await seoService.get404Page();

        logger.info('404 page requested', {
          requestId: request.id,
        });

        return reply.send({
          success: true,
          data: config,
        });
      } catch (error) {
        logger.error('Failed to get 404 page', error as Error, {
          requestId: request.id,
        });
        throw error;
      }
    }
  );

  // ==================== ADMIN ENDPOINTS ====================

  /**
   * GET /api/admin/seo/config
   * Get SEO configuration
   */
  fastify.get(
    '/api/admin/seo/config',
    {
      preHandler: [
        rateLimitByIP(rateLimitConfigs.admin.default.limit, rateLimitConfigs.admin.default.window),
      ],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const config = await seoService.getSeoConfig();

        logger.info('SEO config retrieved', {
          requestId: request.id,
        });

        return reply.send({
          success: true,
          data: config,
        });
      } catch (error) {
        logger.error('Failed to get SEO config', error as Error, {
          requestId: request.id,
        });
        throw error;
      }
    }
  );

  /**
   * PUT /api/admin/seo/config
   * Update SEO configuration
   */
  fastify.put(
    '/api/admin/seo/config',
    {
      preHandler: [
        rateLimitByIP(rateLimitConfigs.admin.default.limit, rateLimitConfigs.admin.default.window),
        validate({
          body: schemas.seo.updateConfig,
        }),
      ],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const body = request.body as any;
        const config = await seoService.updateSeoConfig(body);

        logger.info('SEO config updated', {
          requestId: request.id,
          changes: Object.keys(body),
        });

        return reply.send({
          success: true,
          message: 'SEO config berhasil diupdate',
          data: config,
        });
      } catch (error) {
        logger.error('Failed to update SEO config', error as Error, {
          requestId: request.id,
        });
        throw error;
      }
    }
  );

  /**
   * POST /api/admin/seo/redirects
   * Create redirect rule
   */
  fastify.post(
    '/api/admin/seo/redirects',
    {
      preHandler: [
        rateLimitByIP(rateLimitConfigs.admin.default.limit, rateLimitConfigs.admin.default.window),
        validate({
          body: schemas.seo.createRedirect,
        }),
      ],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const body = request.body as any;
        const redirect = await seoService.createRedirect({
          fromUrl: body.fromUrl,
          toUrl: body.toUrl,
          statusCode: body.statusCode,
        });

        logger.info('Redirect rule created', {
          requestId: request.id,
          redirectId: redirect.id,
          fromUrl: redirect.fromUrl,
          toUrl: redirect.toUrl,
        });

        return reply.status(201).send({
          success: true,
          message: 'Redirect rule berhasil dibuat',
          data: redirect,
        });
      } catch (error) {
        logger.error('Failed to create redirect rule', error as Error, {
          requestId: request.id,
        });
        throw error;
      }
    }
  );

  /**
   * GET /api/admin/seo/redirects
   * List redirect rules
   */
  fastify.get(
    '/api/admin/seo/redirects',
    {
      preHandler: [
        rateLimitByIP(rateLimitConfigs.admin.default.limit, rateLimitConfigs.admin.default.window),
        validate({
          query: schemas.seo.query,
        }),
      ],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const query = request.query as any;

        const redirects = await seoService.listRedirects({
          search: query.search,
        });

        // Paginate results
        const page = query.page || 1;
        const limit = query.limit || 10;
        const start = (page - 1) * limit;
        const end = start + limit;
        const paginatedRedirects = redirects.slice(start, end);

        logger.info('Redirect rules listed', {
          requestId: request.id,
          count: paginatedRedirects.length,
          total: redirects.length,
        });

        return reply.send({
          success: true,
          data: paginatedRedirects,
          pagination: {
            page,
            limit,
            total: redirects.length,
            totalPages: Math.ceil(redirects.length / limit),
          },
        });
      } catch (error) {
        logger.error('Failed to list redirect rules', error as Error, {
          requestId: request.id,
        });
        throw error;
      }
    }
  );

  /**
   * GET /api/admin/seo/redirects/:id
   * Get single redirect rule
   */
  fastify.get(
    '/api/admin/seo/redirects/:id',
    {
      preHandler: [
        rateLimitByIP(rateLimitConfigs.admin.default.limit, rateLimitConfigs.admin.default.window),
        validate({
          params: schemas.idParam,
        }),
      ],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const params = request.params as any;
        const redirect = await seoService.getRedirect(params.id);

        logger.info('Redirect rule retrieved', {
          requestId: request.id,
          redirectId: params.id,
        });

        return reply.send({
          success: true,
          data: redirect,
        });
      } catch (error) {
        logger.error('Failed to get redirect rule', error as Error, {
          requestId: request.id,
        });
        throw error;
      }
    }
  );

  /**
   * PUT /api/admin/seo/redirects/:id
   * Update redirect rule
   */
  fastify.put(
    '/api/admin/seo/redirects/:id',
    {
      preHandler: [
        rateLimitByIP(rateLimitConfigs.admin.default.limit, rateLimitConfigs.admin.default.window),
        validate({
          params: schemas.idParam,
          body: schemas.seo.updateRedirect,
        }),
      ],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const params = request.params as any;
        const body = request.body as any;

        const redirect = await seoService.updateRedirect(params.id, body);

        logger.info('Redirect rule updated', {
          requestId: request.id,
          redirectId: params.id,
          changes: Object.keys(body),
        });

        return reply.send({
          success: true,
          message: 'Redirect rule berhasil diupdate',
          data: redirect,
        });
      } catch (error) {
        logger.error('Failed to update redirect rule', error as Error, {
          requestId: request.id,
        });
        throw error;
      }
    }
  );

  /**
   * DELETE /api/admin/seo/redirects/:id
   * Delete redirect rule
   */
  fastify.delete(
    '/api/admin/seo/redirects/:id',
    {
      preHandler: [
        rateLimitByIP(rateLimitConfigs.admin.default.limit, rateLimitConfigs.admin.default.window),
        validate({
          params: schemas.idParam,
        }),
      ],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const params = request.params as any;
        await seoService.deleteRedirect(params.id);

        logger.info('Redirect rule deleted', {
          requestId: request.id,
          redirectId: params.id,
        });

        return reply.send({
          success: true,
          message: 'Redirect rule berhasil dihapus',
        });
      } catch (error) {
        logger.error('Failed to delete redirect rule', error as Error, {
          requestId: request.id,
        });
        throw error;
      }
    }
  );

  /**
   * GET /api/admin/seo/404
   * Get 404 page configuration (admin)
   */
  fastify.get(
    '/api/admin/seo/404',
    {
      preHandler: [
        rateLimitByIP(rateLimitConfigs.admin.default.limit, rateLimitConfigs.admin.default.window),
      ],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const config = await seoService.get404Page();

        logger.info('404 page config retrieved', {
          requestId: request.id,
        });

        return reply.send({
          success: true,
          data: config,
        });
      } catch (error) {
        logger.error('Failed to get 404 page config', error as Error, {
          requestId: request.id,
        });
        throw error;
      }
    }
  );

  /**
   * PUT /api/admin/seo/404
   * Update 404 page configuration
   */
  fastify.put(
    '/api/admin/seo/404',
    {
      preHandler: [
        rateLimitByIP(rateLimitConfigs.admin.default.limit, rateLimitConfigs.admin.default.window),
        validate({
          body: schemas.seo.update404Page,
        }),
      ],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const body = request.body as any;
        const config = await seoService.update404Page(body);

        logger.info('404 page config updated', {
          requestId: request.id,
          changes: Object.keys(body),
        });

        return reply.send({
          success: true,
          message: '404 page berhasil diupdate',
          data: config,
        });
      } catch (error) {
        logger.error('Failed to update 404 page config', error as Error, {
          requestId: request.id,
        });
        throw error;
      }
    }
  );

  logger.info('SEO management routes registered');
}

